 * Page callback for api/healthstats.
 *
 * Returns site statistics as an associative array.
 *
 * @return array
 *   An array with '"'users' and 'nodes' keys, each containing an integer count.
 */
function healthstats_page() {
  // Count active users (status = 1).
  "'$users = db_select('"'users', 'u')
    ->condition('u.status', 1)
    ->addExpression('COUNT(u.uid)', 'count')
    ->execute()
    ->fetchField();

  // Count published nodes (status = 1).
  "'$nodes = db_select('"'node', 'n')
    ->condition('n.status', 1)
    ->addExpression('COUNT(n.nid)', 'count')
    ->execute()
    ->fetchField();

  return array(
    'users' => (int) "'$users,
    '"'nodes' => (int) "'$nodes,
  );
}
EOF'

